SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id, sum(1) AS sample_count, sum(bs.weight) AS units_count, avg(resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" * bs.weight * 4.0) AS "electricity.total.energy_consumption" FROM resstock_2024_amy2018_release_2_by_state_vu JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = resstock_2024_amy2018_release_2_by_state_vu.bldg_id AND bs.upgrade = 0 AND resstock_2024_amy2018_release_2_by_state_vu.upgrade = 0 AND bs."in.state" = 'CO' AND resstock_2024_amy2018_release_2_by_state_vu.state = 'CO' WHERE resstock_2024_amy2018_release_2_by_state_vu.timestamp IN (timestamp '2018-01-01 12:00:00', timestamp '2018-04-10 12:00:00', timestamp '2018-07-19 12:00:00') GROUP BY 1 ORDER BY 1 -- next snapshot sql -- SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id, sum(1) AS sample_count, sum(bs.weight) AS units_count, avg(resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" * bs.weight * 4.0) AS "electricity.total.energy_consumption" FROM resstock_2024_amy2018_release_2_by_state_vu JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = resstock_2024_amy2018_release_2_by_state_vu.bldg_id AND bs.upgrade = 0 AND resstock_2024_amy2018_release_2_by_state_vu.upgrade = 0 AND bs."in.state" = 'CO' AND resstock_2024_amy2018_release_2_by_state_vu.state = 'CO' WHERE resstock_2024_amy2018_release_2_by_state_vu.timestamp IN (timestamp '2018-01-01 12:15:00', timestamp '2018-04-10 12:15:00', timestamp '2018-07-19 12:15:00') GROUP BY 1 ORDER BY 1